exemplos.python:
while True:
    print("1 - Marcar ponto | 2 - Pedir pausa | 0 - Sair")
    opcao = input("Opção: ")

    if opcao == "1":
        print("Ponto registrado.")
    elif opcao == "2":
        print("Pausa autorizada.")
    elif opcao == "0":
        print("Encerrado.")
        break
    else:
        print("Opção inválida.")

while True:
    idade = int(input("Digite sua idade (positiva): "))
    if idade > 0:
        break
    print("Idade inválida. Tente de novo.")

print(f"Idade aceita: {idade}")

while True:
    print("\n1 - Ver saldo | 2 - Depositar | 0 - Sair")
    escolha = input("Escolha: ")

    if escolha == "1":
        print("Saldo: R$ 1000,00")
    elif escolha == "2":
        print("Depósito registrado.")
    elif escolha == "0":
        break
    else:
        print("Opção inválida.")

while True:
    senha = input("Digite uma senha (mínimo 6 caracteres): ")
    if len(senha) >= 6:
        print("Senha aceita.")
        break
    print("Curta demais. Tente de novo.")
